import React, { useState } from 'react';
import { Link } from 'react-router-dom';

export default function Contact() {
  const [form, setForm] = useState({ name: '', email: '', message: '' });
  const [sent, setSent] = useState(false);
  const [loading, setLoading] = useState(false);

  async function handleSubmit(e) {
  e.preventDefault();

  setLoading(true);

  try {
    const res = await fetch("http://localhost:5000/api/contact", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(form),
    });

    const data = await res.json();

    if (data.success) {
      setSent(true);
    } else {
      alert("Failed to send message");
    }
  } catch (err) {
    console.error(err);
    alert("Server error");
  }

  setLoading(false);
}

  return (
    <div>
      <nav className="public-nav">
        <Link to="/" className="nav-logo">StudentBridge</Link>
        <div className="nav-links"><Link to="/about">About</Link><Link to="/login">Sign In</Link><Link to="/register" className="btn btn-primary btn-sm">Get Started</Link></div>
      </nav>
      <div style={{ maxWidth: 560, margin: '80px auto', padding: '0 24px' }}>
        <h1 style={{ marginBottom: 8 }}>Contact Us</h1>
        <p style={{ marginBottom: 32 }}>Have a question or feedback? We'd love to hear from you.</p>
        {sent
          ? <div className="alert alert-success" style={{ padding: 24, textAlign: 'center' }}>
              <div style={{ fontSize: '2rem', marginBottom: 12 }}>✅</div>
              <h3>Message Sent!</h3>
              <p style={{ marginTop: 8 }}>Thank you for reaching out. We'll get back to you soon.</p>
            </div>
          : <form onSubmit={handleSubmit} className="card">
              <div className="form-group"><label>Full Name</label><input value={form.name} onChange={e => setForm(f => ({ ...f, name: e.target.value }))} required placeholder="Your name" /></div>
              <div className="form-group"><label>Email Address</label><input type="email" value={form.email} onChange={e => setForm(f => ({ ...f, email: e.target.value }))} required placeholder="you@example.com" /></div>
              <div className="form-group"><label>Message</label><textarea value={form.message} onChange={e => setForm(f => ({ ...f, message: e.target.value }))} required placeholder="Your message…" style={{ minHeight: 140 }} /></div>
              <button type="submit" className="btn btn-primary btn-full">Send Message</button>
            </form>
        }
      </div>
    </div>
  );
}
